bool _hostelIsAc(Hostel hostel) {
  final types = hostel.type.map((t) => t.trim().toUpperCase()).toList();
  if (types.any((t) => t == 'NON-AC' || t == 'NON AC')) return false;
  return types.contains('AC');
}

