// LIVE STREAM WEBVIEW SCREEN
// ─────────────────────────────────────────────
class LiveStreamWebViewScreen extends StatefulWidget {
  final String url;
  final String cameraName;

  const LiveStreamWebViewScreen({
    super.key,
    required this.url,
    required this.cameraName,
  });

  @override
  State<LiveStreamWebViewScreen> createState() =>
      _LiveStreamWebViewScreenState();
}

class _LiveStreamWebViewScreenState extends State<LiveStreamWebViewScreen> {
  late final WebViewController _controller;
  bool _isLoading = true;

  @override
  void initState() {
    super.initState();
    _initWebView();
  }

  void _initWebView() {
    // ── Android: allow media autoplay with audio ──────────────────────────
    if (Platform.isAndroid) {
      final androidParams = AndroidWebViewControllerCreationParams();
      final androidController =
          AndroidWebViewController(androidParams);
      // KEY FIX: disable the requirement for a user gesture to start media
      androidController.setMediaPlaybackRequiresUserGesture(false);

      _controller = WebViewController.fromPlatform(androidController);
    } else {
      _controller = WebViewController();
    }

    _controller
      ..setJavaScriptMode(JavaScriptMode.unrestricted)
      ..setBackgroundColor(Colors.black)
      ..setNavigationDelegate(
        NavigationDelegate(
          onPageStarted: (_) => setState(() => _isLoading = true),
          onPageFinished: (url) {
            setState(() => _isLoading = false);
            // After page loads, unmute and try to play any media elements
            _controller.runJavaScript('''
              (function() {
                function tryPlay() {
                  var media = document.querySelectorAll('video, audio');
                  media.forEach(function(el) {
                    el.muted = false;
                    el.volume = 1.0;
                    el.play().catch(function(e) { console.log('play error:', e); });
                  });
                }
                tryPlay();
                // Also attempt after a short delay in case player initialises late
                setTimeout(tryPlay, 1500);
                setTimeout(tryPlay, 3000);
              })();
            ''');
          },
          onWebResourceError: (error) =>
              setState(() => _isLoading = false),
        ),
      )
      ..loadRequest(Uri.parse(widget.url));
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.black,
      appBar: AppBar(
        backgroundColor: const Color(0xFF1A1A2E),
        elevation: 0,
        leading: IconButton(
          icon: const Icon(Icons.arrow_back, color: Colors.white),
          onPressed: () => Navigator.pop(context),
        ),
        title: Row(
          children: [
            Container(
              width: 8,
              height: 8,
              decoration: const BoxDecoration(
                shape: BoxShape.circle,
                color: Colors.greenAccent,
              ),
            ),
            const SizedBox(width: 8),
            Expanded(
              child: Text(
                widget.cameraName,
                style: const TextStyle(
                  color: Colors.white,
                  fontSize: 15,
                  fontWeight: FontWeight.bold,
                ),
                overflow: TextOverflow.ellipsis,
              ),
            ),
          ],
        ),
        actions: [
          Container(
            margin: const EdgeInsets.only(right: 8),
            padding:
                const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
            decoration: BoxDecoration(
              color: Colors.red,
              borderRadius: BorderRadius.circular(4),
            ),
            child: const Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(Icons.circle, color: Colors.white, size: 6),
                SizedBox(width: 4),
                Text(
                  'LIVE',
                  style: TextStyle(
                    color: Colors.white,
                    fontSize: 10,
                    fontWeight: FontWeight.bold,
                    letterSpacing: 1,
                  ),
                ),
              ],
            ),
          ),
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white70),
            onPressed: () => _controller.reload(),
            tooltip: 'Reload',
          ),
        ],
      ),
      body: Stack(
        children: [
          WebViewWidget(controller: _controller),
          if (_isLoading)
            Container(
              color: const Color(0xFF0D1B2A),
              child: const Center(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    CircularProgressIndicator(
                        color: Colors.greenAccent, strokeWidth: 2),
                    SizedBox(height: 12),
                    Text(
                      'Connecting to live stream...',
                      style:
                          TextStyle(color: Colors.white54, fontSize: 13),
                    ),
                  ],
                ),
              ),
            ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────
// SUCCESS OVERLAY
// ─────────────────────────────────────────────
class _SuccessOverlay extends StatefulWidget {
  final String message;
  final VoidCallback onDismiss;
  const _SuccessOverlay({required this.message, required this.onDismiss});
  @override
  State<_SuccessOverlay> createState() => _SuccessOverlayState();
}

class _SuccessOverlayState extends State<_SuccessOverlay>
    with TickerProviderStateMixin {
  late AnimationController _bgController,
      _circleController,
      _checkController,
      _textController;
  late Animation<double> _bgFade, _circleScale, _checkDraw, _textFade;
  late Animation<Offset> _textSlide;

  @override
  void initState() {
    super.initState();
    _bgController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 300),
    );
    _circleController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 500),
    );
    _checkController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 400),
    );
    _textController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 350),
    );

    _bgFade = CurvedAnimation(parent: _bgController, curve: Curves.easeIn);
    _circleScale = CurvedAnimation(
      parent: _circleController,
      curve: Curves.elasticOut,
    );
    _checkDraw =
        CurvedAnimation(parent: _checkController, curve: Curves.easeOut);
    _textFade =
        CurvedAnimation(parent: _textController, curve: Curves.easeIn);
    _textSlide = Tween<Offset>(
      begin: const Offset(0, 0.3),
      end: Offset.zero,
    ).animate(
        CurvedAnimation(parent: _textController, curve: Curves.easeOut));

    _bgController.forward().then(
          (_) => _circleController.forward().then(
                (_) => _checkController.forward().then(
                      (_) => _textController.forward().then(
                            (_) => Future.delayed(
                                const Duration(milliseconds: 1400), () {
                              if (mounted) widget.onDismiss();
                            }),
                          ),
                    ),
              ),
        );
  }

  @override
  void dispose() {
    _bgController.dispose();
    _circleController.dispose();
    _checkController.dispose();
    _textController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return FadeTransition(
      opacity: _bgFade,
      child: Container(
        color: Colors.black.withOpacity(0.55),
        child: Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ScaleTransition(
                scale: _circleScale,
                child: Container(
                  width: 100,
                  height: 100,
                  decoration: BoxDecoration(
                    shape: BoxShape.circle,
                    color: Colors.white,
                    boxShadow: [
                      BoxShadow(
                        color: const Color(0xFFE53935).withOpacity(0.35),
                        blurRadius: 30,
                        spreadRadius: 6,
                      ),
                    ],
                  ),
                  child: AnimatedBuilder(
                    animation: _checkDraw,
                    builder: (_, __) => CustomPaint(
                      painter: _CheckPainter(progress: _checkDraw.value),
                    ),
                  ),
                ),
              ),
              const SizedBox(height: 20),
              SlideTransition(
                position: _textSlide,
                child: FadeTransition(
                  opacity: _textFade,
                  child: Column(
                    children: [
                      Text(
                        widget.message,
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 20,
                          fontWeight: FontWeight.bold,
                          letterSpacing: 0.3,
                        ),
                      ),
                      const SizedBox(height: 6),
                      const Text(
                        'Your hostel is live now!',
                        style:
                            TextStyle(color: Colors.white70, fontSize: 13),
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class _CheckPainter extends CustomPainter {
  final double progress;
  _CheckPainter({required this.progress});
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = const Color(0xFFE53935)
      ..strokeWidth = 5
      ..strokeCap = StrokeCap.round
      ..style = PaintingStyle.stroke;
    final cx = size.width / 2;
    final cy = size.height / 2;
    final p1 = Offset(cx - 18, cy + 2);
    final pMid = Offset(cx - 4, cy + 16);
    final p2 = Offset(cx + 20, cy - 14);
    final seg1Length = (pMid - p1).distance;
    final seg2Length = (p2 - pMid).distance;
    final drawn = progress * (seg1Length + seg2Length);
    final path = Path();
    if (drawn <= seg1Length) {
      final t = drawn / seg1Length;
      path.moveTo(p1.dx, p1.dy);
      path.lineTo(
          p1.dx + (pMid.dx - p1.dx) * t, p1.dy + (pMid.dy - p1.dy) * t);
    } else {
      path.moveTo(p1.dx, p1.dy);
      path.lineTo(pMid.dx, pMid.dy);
      final t = (drawn - seg1Length) / seg2Length;
      path.lineTo(
        pMid.dx + (p2.dx - pMid.dx) * t,
        pMid.dy + (p2.dy - pMid.dy) * t,
      );
    }
    canvas.drawPath(path, paint);
  }

  @override
  bool shouldRepaint(_CheckPainter old) => old.progress != progress;
}

