                            ? const Center(
                                child: Text('No banners available'))
                            : PageView.builder(
                                controller: _carouselController,
                                itemCount: _carouselImages.length,
                                onPageChanged: (i) =>
                                    setState(() => _carouselPage = i),
                                itemBuilder: (_, index) => Padding(
                                  padding: const EdgeInsets.symmetric(
