                    child: RichText(
                      text: const TextSpan(
                        children: [
                          TextSpan(
                            text: 'Camera ',
                            style: TextStyle(
                              color: Color(0xFFE53935),
                              fontWeight: FontWeight.bold,
                              fontSize: 16,
                            ),
                          ),
                          TextSpan(
                            text: 'Capturing',
                            style: TextStyle(
                              color: Colors.black,
                              fontWeight: FontWeight.bold,
                              fontSize: 16,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),

                  Consumer3<HostelProvider, CameraProvider,
                      StreamCameraProvider>(
                    builder: (context, hostelProvider, cameraProvider,
                        streamProvider, _) {
                      final hostels = hostelProvider.hostels;
                      if (hostels.isEmpty) {
                        return Padding(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 16, vertical: 8),
                          child: _AddCameraCard(
                            onTap: null,
                            label: 'Add a hostel first to add cameras',
                          ),
                        );
                      }

                      final hostel = hostels.first;

                      return Padding(
                        padding: const EdgeInsets.symmetric(
                            horizontal: 16, vertical: 8),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            if (cameraProvider.cameras.isNotEmpty)
                              SizedBox(
                                height: 100,
                                child: ListView.builder(
                                  scrollDirection: Axis.horizontal,
                                  itemCount: cameraProvider.cameras.length,
                                  itemBuilder: (_, i) {
                                    final cam = cameraProvider.cameras[i];
                                    final streamData = streamProvider
                                        .getStreamForCamera(cam.cameraId);
                                    return GestureDetector(
                                      onTap: () {
                                        cameraProvider.getSingleCamera(
                                          hostelId: hostel.id,
                                          cameraId: cam.cameraId,
                                        );
                                        Navigator.push(
                                          context,
                                          MaterialPageRoute(
                                            builder: (_) => MultiProvider(
                                              providers: [
                                                ChangeNotifierProvider.value(
                                                    value: cameraProvider),
                                                ChangeNotifierProvider.value(
                                                    value: streamProvider),
                                              ],
                                              child: CameraDetailsScreen(
                                                hostelId: hostel.id,
                                                camera: cam,
                                              ),
                                            ),
                                          ),
                                        );
                                      },
                                      child: _CameraThumbCard(
                                        camera: cam,
                                        streamData: streamData,
                                      ),
                                    );
                                  },
                                ),
                              ),

                            if (cameraProvider.cameras.isNotEmpty) ...[
                              const SizedBox(height: 12),
                              _LiveStreamCompactPanel(
                                hostelId: hostel.id,
                                cameras: cameraProvider.cameras,
                                streamProvider: streamProvider,
                              ),
                            ],

                            const SizedBox(height: 10),
                            _AddCameraCard(
                              onTap: () => _openAddCameraSheet(hostel.id),
                              label: 'Add Your Camera',
                            ),
                          ],
                        ),
                      );
                    },
                  ),

                  // ── Hifi heading + Monthly/Daily toggle ──────────────────
                  Padding(
                    padding: const EdgeInsets.symmetric(
                        horizontal: 16, vertical: 4),
                    child: Row(
                      mainAxisAlignment: MainAxisAlignment.spaceBetween,
                      children: [
                        RichText(
                          text: const TextSpan(
                            children: [
                              TextSpan(
                                text: 'Hifi ',
                                style: TextStyle(
                                  color: Color(0xFFE53935),
                                  fontWeight: FontWeight.bold,
                                  fontSize: 16,
                                ),
                              ),
                              TextSpan(
                                text: 'Details',
                                style: TextStyle(
                                  color: Colors.black,
                                  fontWeight: FontWeight.bold,
                                  fontSize: 16,
                                ),
                              ),
                            ],
                          ),
                        ),
                        Container(
                          decoration: BoxDecoration(
                            color: Colors.grey.shade100,
                            borderRadius: BorderRadius.circular(20),
                            border: Border.all(color: Colors.grey.shade300),
                          ),
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              _PriceToggleChip(
                                label: 'Monthly',
                                selected: !_showDailyPrice,
                                onTap: () =>
                                    setState(() => _showDailyPrice = false),
                              ),
                              _PriceToggleChip(
                                label: 'Daily',
                                selected: _showDailyPrice,
                                onTap: () =>
                                    setState(() => _showDailyPrice = true),
                              ),
                            ],
                          ),
                        ),
                      ],
                    ),
                  ),

                  // ── Hostel cards ─────────────────────────────────────────
                  Consumer<HostelProvider>(
                    builder: (context, provider, _) {
                      if (provider.isLoading)
                        return const Padding(
                          padding: EdgeInsets.symmetric(vertical: 20),
                          child: Center(child: CircularProgressIndicator()),
                        );
                      if (provider.hasError)
                        return Padding(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 16, vertical: 10),
                          child: Text(
                            provider.errorMessage ?? 'Something went wrong',
                            style: const TextStyle(color: Colors.red),
                          ),
                        );
                      return Column(
                        children: provider.hostels
                            .map(
                              (hostel) => Padding(
                                padding: const EdgeInsets.symmetric(
                                    horizontal: 16, vertical: 6),
                                child: GestureDetector(
                                  onTap: () => Navigator.push(
                                    context,
                                    MaterialPageRoute(
                                      builder: (_) => HostelDetails(
                                        hostel: hostel,
                                        qrUrl: hostel.qrUrl,
                                      ),
                                    ),
                                  ),
                                  child: _HifiHostelCard(
                                    hostel: hostel,
                                    showDailyPrice: _showDailyPrice,
                                    isDeleting: provider.isDeleting &&
                                        provider.deletingHostelId == hostel.id,
                                    onEdit: () => _openEditHostel(hostel),
                                    onDelete: () => _deleteHostel(hostel),
                                  ),
                                ),
                              ),
                            )
                            .toList(),
                      );
                    },
                  ),

                  GestureDetector(
                    onTap: _openCreateHostel,
                    child: Padding(
                      padding: const EdgeInsets.symmetric(
                          horizontal: 16, vertical: 8),
                      child: Container(
                        width: double.infinity,
                        height: 90,
                        decoration: BoxDecoration(
                          border: Border.all(color: Colors.grey.shade300),
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: const Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            Icon(Icons.add, size: 32, color: Colors.black54),
                            SizedBox(height: 6),
                            Text(
                              'Add Details',
                              style: TextStyle(
                                  fontSize: 14, color: Colors.black54),
                            ),
                          ],
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 80),
                ],
              ),
            ),
          ),
        ),
        if (_showSuccessOverlay)
          Positioned.fill(
            child: _SuccessOverlay(
              message: _successMessage,
              onDismiss: _dismissSuccess,
            ),
          ),
      ],
    );
  }
}

// ─────────────────────────────────────────────
// LIVE STREAM COMPACT PANEL
// ─────────────────────────────────────────────
class _LiveStreamCompactPanel extends StatefulWidget {
  final String hostelId;
  final List<CameraModel> cameras;
  final StreamCameraProvider streamProvider;

  const _LiveStreamCompactPanel({
    required this.hostelId,
    required this.cameras,
    required this.streamProvider,
  });

  @override
  State<_LiveStreamCompactPanel> createState() =>
      _LiveStreamCompactPanelState();
}

class _LiveStreamCompactPanelState extends State<_LiveStreamCompactPanel> {
  int _selectedIndex = 0;

  CameraModel get _selectedCamera => widget.cameras[_selectedIndex];

  LiveStreamModel? get _currentStream =>
      widget.streamProvider.getStreamForCamera(_selectedCamera.cameraId);

  void _openWebView(String url, String name) {
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) =>
            LiveStreamWebViewScreen(url: url, cameraName: name),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final stream = _currentStream;

    return Container(
      decoration: BoxDecoration(
        gradient: const LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: [Color(0xFF1A1A2E), Color(0xFF16213E)],
        ),
        borderRadius: BorderRadius.circular(14),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Header ──
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 12, 14, 8),
            child: Row(
              children: [
                Container(
                  width: 8,
                  height: 8,
                  decoration: BoxDecoration(
                    shape: BoxShape.circle,
                    color: stream?.isStreaming == true
                        ? Colors.greenAccent
                        : Colors.red,
                    boxShadow: [
                      if (stream?.isStreaming == true)
                        BoxShadow(
                          color: Colors.greenAccent.withOpacity(0.6),
                          blurRadius: 6,
                          spreadRadius: 2,
                        ),
                    ],
                  ),
                ),
                const SizedBox(width: 8),
                const Text(
                  'Live Stream',
                  style: TextStyle(
                    color: Colors.white,
                    fontWeight: FontWeight.bold,
                    fontSize: 13,
                  ),
                ),
                const Spacer(),
                if (widget.streamProvider.isLoading)
                  const SizedBox(
                    width: 14,
                    height: 14,
                    child: CircularProgressIndicator(
                        color: Colors.white54, strokeWidth: 1.5),
                  ),
              ],
            ),
          ),

          // ── Camera selector tabs ──
          if (widget.cameras.length > 1)
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 14),
              child: SingleChildScrollView(
                scrollDirection: Axis.horizontal,
                child: Row(
                  children: List.generate(widget.cameras.length, (i) {
                    final cam = widget.cameras[i];
                    final isSelected = i == _selectedIndex;
                    final s = widget.streamProvider
                        .getStreamForCamera(cam.cameraId);
                    return GestureDetector(
                      onTap: () => setState(() => _selectedIndex = i),
                      child: AnimatedContainer(
                        duration: const Duration(milliseconds: 200),
                        margin: const EdgeInsets.only(right: 8, bottom: 8),
                        padding: const EdgeInsets.symmetric(
                            horizontal: 10, vertical: 5),
                        decoration: BoxDecoration(
                          color: isSelected
                              ? const Color(0xFFE53935)
                              : Colors.white12,
                          borderRadius: BorderRadius.circular(20),
                          border: Border.all(
                            color: isSelected
                                ? const Color(0xFFE53935)
                                : Colors.white24,
                          ),
                        ),
                        child: Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            Container(
                              width: 6,
                              height: 6,
                              decoration: BoxDecoration(
                                shape: BoxShape.circle,
                                color: s?.isStreaming == true
                                    ? Colors.greenAccent
                                    : Colors.red,
                              ),
                            ),
                            const SizedBox(width: 5),
                            Text(
                              cam.name,
                              style: TextStyle(
                                color: isSelected
                                    ? Colors.white
                                    : Colors.white70,
                                fontSize: 10,
                                fontWeight: isSelected
                                    ? FontWeight.bold
                                    : FontWeight.normal,
                              ),
                            ),
                          ],
                        ),
                      ),
                    );
                  }),
                ),
              ),
            ),

          // ── Stream info + Watch Live button ──
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 0, 14, 12),
            child: Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.05),
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.white12),
              ),
              child: Row(
                children: [
                  Container(
                    width: 44,
                    height: 44,
                    decoration: BoxDecoration(
                      color: stream?.isStreaming == true
                          ? Colors.greenAccent.withOpacity(0.12)
                          : Colors.red.withOpacity(0.12),
                      shape: BoxShape.circle,
                    ),
                    child: Icon(
                      stream?.isStreaming == true
                          ? Icons.videocam
                          : Icons.videocam_off_outlined,
                      color: stream?.isStreaming == true
                          ? Colors.greenAccent
                          : Colors.redAccent,
                      size: 22,
                    ),
                  ),
                  const SizedBox(width: 12),
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          _selectedCamera.name,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 12,
                            fontWeight: FontWeight.bold,
                          ),
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                        ),
                        const SizedBox(height: 3),
                        Row(
                          children: [
                            if (stream?.channel.isNotEmpty == true) ...[
                              const SizedBox(width: 6),
                              Text(
                                'Ch ${stream!.channel}',
                                style: const TextStyle(
                                    color: Colors.white38, fontSize: 10),
                              ),
                            ],
                          ],
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 10),
                  GestureDetector(
                    onTap: () {
                      final url = stream?.directPlayUrl ?? '';
                      if (url.isEmpty) {
                        ScaffoldMessenger.of(context).showSnackBar(
                          const SnackBar(
                            content: Text('Stream URL not available'),
                            backgroundColor: Colors.red,
                          ),
                        );
                        return;
                      }
                      _openWebView(url, _selectedCamera.name);
                    },
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                          horizontal: 12, vertical: 8),
                      decoration: BoxDecoration(
                        color: const Color(0xFFE53935),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: const Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(Icons.play_circle_fill,
                              color: Colors.white, size: 20),
                          SizedBox(height: 3),
                          Text(
                            'Watch\nLive',
                            textAlign: TextAlign.center,
                            style: TextStyle(
                              color: Colors.white,
                              fontSize: 9,
                              fontWeight: FontWeight.bold,
                              height: 1.2,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),

          if (stream != null)
            _UnknownDetectionBar(detection: stream.unknownUserDetection),

          const SizedBox(height: 4),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────
// UNKNOWN DETECTION BAR
// ─────────────────────────────────────────────
class _UnknownDetectionBar extends StatelessWidget {
  final UnknownUserDetection detection;
  const _UnknownDetectionBar({required this.detection});

  @override
  Widget build(BuildContext context) {
    final hasUnknown = detection.hasUnknownUser;
    return Padding(
      padding: const EdgeInsets.fromLTRB(14, 0, 14, 8),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
        decoration: BoxDecoration(
          color: hasUnknown
              ? Colors.red.withOpacity(0.15)
              : Colors.green.withOpacity(0.1),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(
            color: hasUnknown
                ? Colors.red.withOpacity(0.4)
                : Colors.greenAccent.withOpacity(0.3),
          ),
        ),
        child: Row(
          children: [
            Icon(
              hasUnknown
                  ? Icons.warning_amber_rounded
                  : Icons.shield_outlined,
              color: hasUnknown ? Colors.redAccent : Colors.greenAccent,
              size: 16,
            ),
            const SizedBox(width: 8),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'Registered: ${detection.registeredUsersCount}  •  Interval: ${detection.detectionInterval}',
                    style:
                        const TextStyle(color: Colors.white38, fontSize: 9),
                  ),
                ],
              ),
            ),
            if (hasUnknown)
              Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                decoration: BoxDecoration(
                  color: Colors.redAccent,
                  borderRadius: BorderRadius.circular(4),
                ),
                child: Text(
                  '${detection.unknownCount}',
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 11,
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }
}

