  @override
  void dispose() {
    _nameCtrl.dispose();
    _ipCtrl.dispose();
    _portCtrl.dispose();
    _userCtrl.dispose();
    _passCtrl.dispose();
    _locationCtrl.dispose();
    _manufacturerCtrl.dispose();
    _channelCtrl.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;
    final provider = context.read<CameraProvider>();
    final payload = CameraPayload(
      name: _nameCtrl.text.trim(),
      ipAddress: _ipCtrl.text.trim(),
      port: int.tryParse(_portCtrl.text.trim()) ?? 554,
      username: _userCtrl.text.trim(),
      password: _passCtrl.text.trim(),
      location: _locationCtrl.text.trim(),
      manufacturer: _manufacturerCtrl.text.trim(),
      channel: int.tryParse(_channelCtrl.text.trim()) ?? 1,
    );
    final success = await provider.addCamera(
      hostelId: widget.hostelId,
      payload: payload,
    );
    if (!mounted) return;
    if (success) {
      Navigator.pop(context);
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Camera added successfully'),
          backgroundColor: Colors.green,
        ),
      );
    } else {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(provider.errorMessage),
          backgroundColor: Colors.red,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: EdgeInsets.only(
        left: 20,
        right: 20,
        top: 20,
        bottom: MediaQuery.of(context).viewInsets.bottom + 24,
      ),
      child: Form(
        key: _formKey,
        child: SingleChildScrollView(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Center(
                child: Container(
                  width: 40,
                  height: 4,
                  decoration: BoxDecoration(
                    color: Colors.grey.shade300,
                    borderRadius: BorderRadius.circular(2),
                  ),
                ),
              ),
              const SizedBox(height: 16),
              RichText(
                text: const TextSpan(
                  children: [
                    TextSpan(
                      text: 'Add ',
                      style: TextStyle(
                        color: Color(0xFFE53935),
                        fontWeight: FontWeight.bold,
                        fontSize: 18,
                      ),
                    ),
                    TextSpan(
                      text: 'Camera',
                      style: TextStyle(
                        color: Colors.black,
                        fontWeight: FontWeight.bold,
                        fontSize: 18,
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(height: 4),
              Text(
                'Fill in the camera connection details',
                style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
              ),
              const SizedBox(height: 20),
              _SheetField(
                controller: _nameCtrl,
                label: 'Camera Name',
                hint: 'e.g. Main Gate Camera',
                icon: Icons.videocam_outlined,
                validator: (v) =>
                    v == null || v.isEmpty ? 'Name is required' : null,
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _ipCtrl,
                label: 'IP Address',
                hint: 'e.g. 192.168.1.100',
                icon: Icons.router_outlined,
                keyboardType: TextInputType.number,
                validator: (v) =>
                    v == null || v.isEmpty ? 'IP address is required' : null,
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _portCtrl,
                label: 'Port',
                hint: '554',
                icon: Icons.settings_ethernet,
                keyboardType: TextInputType.number,
                validator: (v) {
                  if (v == null || v.isEmpty) return 'Port is required';
                  if (int.tryParse(v) == null) return 'Enter a valid port';
                  return null;
                },
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _userCtrl,
                label: 'Username',
                hint: 'admin',
                icon: Icons.person_outline,
                validator: (v) =>
                    v == null || v.isEmpty ? 'Username is required' : null,
              ),
              const SizedBox(height: 12),
              TextFormField(
                controller: _passCtrl,
                obscureText: _obscurePass,
                decoration: InputDecoration(
                  labelText: 'Password',
                  hintText: 'Enter password',
                  prefixIcon: const Icon(Icons.lock_outline,
                      color: Color(0xFFE53935), size: 20),
                  suffixIcon: GestureDetector(
                    onTap: () =>
                        setState(() => _obscurePass = !_obscurePass),
                    child: Icon(
                      _obscurePass
                          ? Icons.visibility_off_outlined
                          : Icons.visibility_outlined,
                      size: 20,
                      color: Colors.grey,
                    ),
                  ),
                  labelStyle:
                      const TextStyle(fontSize: 13, color: Colors.black54),
                  contentPadding: const EdgeInsets.symmetric(
                      horizontal: 14, vertical: 12),
                  enabledBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: BorderSide(color: Colors.grey.shade300),
                  ),
                  focusedBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: const BorderSide(color: Color(0xFFE53935)),
                  ),
                  errorBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: const BorderSide(color: Colors.red),
                  ),
                  focusedErrorBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: const BorderSide(color: Colors.red),
                  ),
                ),
                validator: (v) =>
                    v == null || v.isEmpty ? 'Password is required' : null,
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _locationCtrl,
                label: 'Location',
                hint: 'e.g. Front Entrance',
                icon: Icons.location_on_outlined,
                validator: (v) =>
                    v == null || v.isEmpty ? 'Location is required' : null,
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _manufacturerCtrl,
                label: 'Manufacturer',
                hint: 'e.g. Hikvision, Dahua, CP Plus',
                icon: Icons.business_outlined,
                validator: (v) => v == null || v.isEmpty
                    ? 'Manufacturer is required'
                    : null,
              ),
              const SizedBox(height: 12),
              _SheetField(
                controller: _channelCtrl,
                label: 'Channel',
                hint: 'e.g. 1',
                icon: Icons.cable_outlined,
                keyboardType: TextInputType.number,
                validator: (v) {
                  if (v == null || v.isEmpty) return 'Channel is required';
                  if (int.tryParse(v) == null)
                    return 'Enter a valid channel number';
                  return null;
                },
              ),
              const SizedBox(height: 24),
              Consumer<CameraProvider>(
                builder: (_, provider, __) => SizedBox(
                  width: double.infinity,
                  child: ElevatedButton(
                    style: ElevatedButton.styleFrom(
                      backgroundColor: const Color(0xFFE53935),
                      foregroundColor: Colors.white,
                      padding: const EdgeInsets.symmetric(vertical: 14),
                      shape: RoundedRectangleBorder(
                        borderRadius: BorderRadius.circular(12),
                      ),
                    ),
                    onPressed: provider.isLoading ? null : _submit,
                    child: provider.isLoading
                        ? const SizedBox(
                            height: 20,
                            width: 20,
                            child: CircularProgressIndicator(
                                color: Colors.white, strokeWidth: 2),
                          )
                        : const Text(
                            'Add Camera',
                            style: TextStyle(
                                fontSize: 15, fontWeight: FontWeight.bold),
                          ),
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────
// REUSABLE SHEET FIELD
// ─────────────────────────────────────────────
class _SheetField extends StatelessWidget {
  final TextEditingController controller;
  final String label;
  final String hint;
  final IconData icon;
  final TextInputType keyboardType;
  final String? Function(String?)? validator;

  const _SheetField({
    required this.controller,
    required this.label,
    required this.hint,
    required this.icon,
    this.keyboardType = TextInputType.text,
    this.validator,
  });

  @override
  Widget build(BuildContext context) {
    return TextFormField(
      controller: controller,
      keyboardType: keyboardType,
      validator: validator,
      decoration: InputDecoration(
        labelText: label,
        hintText: hint,
        prefixIcon: Icon(icon, color: const Color(0xFFE53935), size: 20),
        labelStyle: const TextStyle(fontSize: 13, color: Colors.black54),
        contentPadding:
            const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
        enabledBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(10),
          borderSide: BorderSide(color: Colors.grey.shade300),
        ),
        focusedBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(10),
          borderSide: const BorderSide(color: Color(0xFFE53935)),
        ),
        errorBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(10),
          borderSide: const BorderSide(color: Colors.red),
        ),
        focusedErrorBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(10),
          borderSide: const BorderSide(color: Colors.red),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────
// CAMERA DETAILS SCREEN
// ─────────────────────────────────────────────
class CameraDetailsScreen extends StatefulWidget {
  final String hostelId;
  final CameraModel camera;

  const CameraDetailsScreen({
    super.key,
    required this.hostelId,
    required this.camera,
  });

  @override
  State<CameraDetailsScreen> createState() => _CameraDetailsScreenState();
}

class _CameraDetailsScreenState extends State<CameraDetailsScreen> {
  late CameraModel _camera;

  @override
  void initState() {
    super.initState();
    _camera = widget.camera;
    WidgetsBinding.instance.addPostFrameCallback((_) => _fetchDetails());
  }

  Future<void> _fetchDetails() async {
    final provider = context.read<CameraProvider>();
    await provider.getSingleCamera(
      hostelId: widget.hostelId,
      cameraId: _camera.cameraId,
    );
    if (mounted && provider.selectedCamera != null) {
      setState(() => _camera = provider.selectedCamera!);
    }

    final token = await SharedPreferenceHelper.getToken() ?? '';
    if (mounted) {
      await context.read<StreamCameraProvider>().fetchLiveStream(
            hostelId: widget.hostelId,
            cameraId: _camera.cameraId,
            token: token,
          );
    }
  }

  void _openEditCameraSheet() {
    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      builder: (_) => ChangeNotifierProvider.value(
        value: context.read<CameraProvider>(),
        child: _EditCameraSheet(
          hostelId: widget.hostelId,
          camera: _camera,
          onUpdated: (updated) => setState(() => _camera = updated),
        ),
      ),
    );
  }

  Future<void> _confirmDelete() async {
    final confirmed = await showDialog<bool>(
      context: context,
      barrierDismissible: false,
      builder: (ctx) => Dialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        child: Padding(
          padding: const EdgeInsets.all(24),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Container(
                width: 64,
                height: 64,
                decoration: BoxDecoration(
                  color: Colors.red.shade50,
                  shape: BoxShape.circle,
                ),
                child: const Icon(Icons.delete_outline,
                    color: Color(0xFFE53935), size: 32),
              ),
              const SizedBox(height: 16),
              const Text('Delete Camera',
                  style:
                      TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
              const SizedBox(height: 8),
              Text(
                'Are you sure you want to delete "${_camera.name}"? This cannot be undone.',
                textAlign: TextAlign.center,
                style: const TextStyle(fontSize: 13, color: Colors.black54),
              ),
              const SizedBox(height: 24),
              Row(
                children: [
                  Expanded(
                    child: OutlinedButton(
                      style: OutlinedButton.styleFrom(
                        padding: const EdgeInsets.symmetric(vertical: 12),
                        side: BorderSide(color: Colors.grey.shade300),
                        shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(8)),
                      ),
                      onPressed: () => Navigator.pop(ctx, false),
                      child: const Text('Cancel',
                          style: TextStyle(color: Colors.black54)),
                    ),
                  ),
                  const SizedBox(width: 12),
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFE53935),
                        foregroundColor: Colors.white,
                        padding: const EdgeInsets.symmetric(vertical: 12),
                        shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(8)),
                      ),
                      onPressed: () => Navigator.pop(ctx, true),
                      child: const Text('Delete'),
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );

    if (confirmed != true || !mounted) return;

    final provider = context.read<CameraProvider>();
    final success = await provider.deleteCamera(
      hostelId: widget.hostelId,
      cameraId: _camera.cameraId,
    );

    if (!mounted) return;
    if (success) {
      Navigator.pop(context);
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Camera deleted successfully'),
          backgroundColor: Colors.green,
        ),
      );
    } else {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(provider.errorMessage),
          backgroundColor: Colors.red,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.white,
      appBar: AppBar(
        backgroundColor: Colors.white,
        elevation: 0,
        leading: IconButton(
          icon: const Icon(Icons.arrow_back, color: Colors.black),
          onPressed: () => Navigator.pop(context),
        ),
        title: RichText(
          text: const TextSpan(
            children: [
              TextSpan(
                text: 'Camera ',
                style: TextStyle(
                  color: Color(0xFFE53935),
                  fontWeight: FontWeight.bold,
                  fontSize: 18,
                ),
              ),
              TextSpan(
                text: 'Details',
                style: TextStyle(
                  color: Colors.black,
                  fontWeight: FontWeight.bold,
                  fontSize: 18,
                ),
              ),
            ],
          ),
        ),
        actions: [
          Consumer<CameraProvider>(
            builder: (_, provider, __) => provider.isLoading
                ? const Padding(
                    padding: EdgeInsets.all(14),
                    child: SizedBox(
                      width: 20,
                      height: 20,
                      child: CircularProgressIndicator(
                          color: Color(0xFFE53935), strokeWidth: 2),
                    ),
                  )
                : Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      IconButton(
                        icon: const Icon(Icons.edit_outlined,
                            color: Color(0xFFE53935)),
                        onPressed: _openEditCameraSheet,
                        tooltip: 'Edit Camera',
                      ),
                      IconButton(
                        icon: const Icon(Icons.delete_outline,
                            color: Color(0xFFE53935)),
                        onPressed: _confirmDelete,
                        tooltip: 'Delete Camera',
                      ),
                    ],
                  ),
          ),
        ],
      ),
      body: Consumer2<CameraProvider, StreamCameraProvider>(
        builder: (_, cameraProvider, streamProvider, __) {
          if (cameraProvider.isLoading &&
              cameraProvider.selectedCamera == null) {
            return const Center(child: CircularProgressIndicator());
          }

          final cam = cameraProvider.selectedCamera ?? _camera;
          final streamData =
              streamProvider.getStreamForCamera(cam.cameraId) ??
                  streamProvider.liveStream;

          return SingleChildScrollView(
            padding: const EdgeInsets.all(20),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                _CameraDetailStreamCard(
                  stream: streamData,
                  cameraName: cam.name,
                  isLoadingStream: streamProvider.isLoadingToggle,
                ),

                const SizedBox(height: 20),
                const SizedBox(height: 24),

                const Text(
                  'Connection Details',
                  style: TextStyle(fontSize: 15, fontWeight: FontWeight.bold),
                ),
                const SizedBox(height: 12),

                _DetailCard(
                  items: [
                    _DetailItem(
                        icon: Icons.router_outlined,
                        label: 'IP Address',
                        value: cam.ipAddress),
                    _DetailItem(
                        icon: Icons.settings_ethernet,
                        label: 'Port',
                        value: cam.port.toString()),
                    _DetailItem(
                        icon: Icons.person_outline,
                        label: 'Username',
                        value: cam.username),
                    _DetailItem(
                        icon: Icons.lock_outline,
                        label: 'Password',
                        value: '••••••••'),
                  ],
                ),

                const SizedBox(height: 16),
                const Text(
                  'Location & Stream',
                  style: TextStyle(fontSize: 15, fontWeight: FontWeight.bold),
                ),
                const SizedBox(height: 12),

                _DetailCard(
                  items: [
                    _DetailItem(
                        icon: Icons.location_on_outlined,
                        label: 'Location',
                        value: cam.location),
                    _DetailItem(
                        icon: Icons.stream,
                        label: 'Stream URL',
                        value: cam.streamUrl,
                        isUrl: true),
                  ],
                ),

                const SizedBox(height: 16),
                const Text(
                  'System Info',
                  style: TextStyle(fontSize: 15, fontWeight: FontWeight.bold),
                ),
                const SizedBox(height: 12),

                _DetailCard(
                  items: [
                    _DetailItem(
                        icon: Icons.badge_outlined,
                        label: 'Camera ID',
                        value: cam.cameraId),
                    _DetailItem(
                      icon: Icons.calendar_today_outlined,
                      label: 'Added On',
                      value:
                          '${cam.createdAt.day}/${cam.createdAt.month}/${cam.createdAt.year}',
                    ),
                  ],
                ),

                const SizedBox(height: 28),

                Consumer<CameraProvider>(
                  builder: (_, provider, __) => Row(
                    children: [
                      Expanded(
                        child: ElevatedButton.icon(
                          style: ElevatedButton.styleFrom(
                            backgroundColor: const Color(0xFFE53935),
                            foregroundColor: Colors.white,
                            padding: const EdgeInsets.symmetric(vertical: 14),
                            shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(12)),
                          ),
                          onPressed:
                              provider.isLoading ? null : _openEditCameraSheet,
                          icon:
                              const Icon(Icons.edit_outlined, size: 18),
                          label: const Text('Edit Camera',
                              style: TextStyle(
                                  fontSize: 14,
                                  fontWeight: FontWeight.bold)),
                        ),
                      ),
                      const SizedBox(width: 12),
                      Expanded(
                        child: OutlinedButton.icon(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: const Color(0xFFE53935),
                            side: const BorderSide(
                                color: Color(0xFFE53935)),
                            padding: const EdgeInsets.symmetric(vertical: 14),
                            shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(12)),
                          ),
                          onPressed:
                              provider.isLoading ? null : _confirmDelete,
                          icon: provider.isLoading
                              ? const SizedBox(
                                  width: 16,
                                  height: 16,
                                  child: CircularProgressIndicator(
                                      color: Color(0xFFE53935),
                                      strokeWidth: 2),
                                )
                              : const Icon(Icons.delete_outline, size: 18),
                          label: Text(
                            provider.isLoading ? 'Deleting...' : 'Delete',
                            style: const TextStyle(
                                fontSize: 14, fontWeight: FontWeight.bold),
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 20),
              ],
            ),
          );
        },
      ),
    );
  }
}

// ─────────────────────────────────────────────
// CAMERA DETAIL STREAM CARD
// ─────────────────────────────────────────────
class _CameraDetailStreamCard extends StatelessWidget {
  final LiveStreamModel? stream;
  final String cameraName;
  final bool isLoadingStream;

  const _CameraDetailStreamCard({
    required this.stream,
    required this.cameraName,
    required this.isLoadingStream,
  });

  void _openWebView(BuildContext context, String url) {
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) =>
            LiveStreamWebViewScreen(url: url, cameraName: cameraName),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      width: double.infinity,
      decoration: BoxDecoration(
        gradient: const LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: [Color(0xFF1A1A2E), Color(0xFF16213E)],
        ),
        borderRadius: BorderRadius.circular(14),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 12, 14, 10),
            child: Row(
              children: [
                Container(
                  width: 8,
                  height: 8,
                  decoration: BoxDecoration(
                    shape: BoxShape.circle,
                    color: stream?.isStreaming == true
                        ? Colors.greenAccent
                        : Colors.red,
                    boxShadow: [
                      if (stream?.isStreaming == true)
                        BoxShadow(
                          color: Colors.greenAccent.withOpacity(0.6),
                          blurRadius: 6,
                          spreadRadius: 2,
                        ),
                    ],
                  ),
                ),
                const SizedBox(width: 8),
                const Text(
                  'Live Stream Status',
                  style: TextStyle(
                    color: Colors.white,
                    fontWeight: FontWeight.bold,
                    fontSize: 13,
                  ),
                ),
                const Spacer(),
                if (isLoadingStream)
                  const SizedBox(
                    width: 14,
                    height: 14,
                    child: CircularProgressIndicator(
                        color: Colors.white54, strokeWidth: 1.5),
                  ),
              ],
            ),
          ),

          Padding(
            padding: const EdgeInsets.fromLTRB(14, 0, 14, 12),
            child: isLoadingStream && stream == null
                ? Container(
                    height: 80,
                    decoration: BoxDecoration(
                      color: Colors.black26,
                      borderRadius: BorderRadius.circular(10),
                    ),
                    child: const Center(
                      child:
                          CircularProgressIndicator(color: Colors.white54),
                    ),
                  )
                : stream == null
                    ? Container(
                        height: 80,
                        decoration: BoxDecoration(
                          color: Colors.black26,
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: const Center(
                          child: Text('Stream data unavailable',
                              style: TextStyle(
                                  color: Colors.white38, fontSize: 12)),
                        ),
                      )
                    : Container(
                        padding: const EdgeInsets.all(14),
                        decoration: BoxDecoration(
                          color: Colors.white.withOpacity(0.05),
                          borderRadius: BorderRadius.circular(10),
                          border: Border.all(
                            color: stream!.isStreaming
                                ? Colors.greenAccent.withOpacity(0.3)
                                : Colors.white12,
                          ),
                        ),
                        child: Row(
                          children: [
                            Container(
                              width: 48,
                              height: 48,
                              decoration: BoxDecoration(
                                color: stream!.isStreaming
                                    ? Colors.greenAccent.withOpacity(0.12)
                                    : Colors.redAccent.withOpacity(0.12),
                                shape: BoxShape.circle,
                              ),
                              child: Icon(
                                stream!.isStreaming
                                    ? Icons.videocam
                                    : Icons.videocam_off_outlined,
                                color: stream!.isStreaming
                                    ? Colors.greenAccent
                                    : Colors.redAccent,
                                size: 24,
                              ),
                            ),
                            const SizedBox(width: 12),
                            Expanded(
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: [
                                  Row(
                                    children: [
                                      if (stream!.channel.isNotEmpty) ...[
                                        const SizedBox(width: 8),
                                        Text(
                                          'Ch ${stream!.channel}',
                                          style: const TextStyle(
                                              color: Colors.white54,
                                              fontSize: 11),
                                        ),
                                      ],
                                    ],
                                  ),
                                ],
                              ),
                            ),
                            const SizedBox(width: 10),
                            GestureDetector(
                              onTap: () {
                                final url = stream!.directPlayUrl;
                                if (url.isEmpty) {
                                  ScaffoldMessenger.of(context).showSnackBar(
                                    const SnackBar(
                                      content:
                                          Text('Stream URL not available'),
                                      backgroundColor: Colors.red,
                                    ),
                                  );
                                  return;
                                }
                                _openWebView(context, url);
                              },
                              child: Container(
                                padding: const EdgeInsets.symmetric(
                                    horizontal: 14, vertical: 10),
                                decoration: BoxDecoration(
                                  color: const Color(0xFFE53935),
                                  borderRadius: BorderRadius.circular(10),
                                ),
                                child: const Column(
                                  mainAxisSize: MainAxisSize.min,
