// ─────────────────────────────────────────────
// HIFI HOSTEL CARD
// ─────────────────────────────────────────────
class _HifiHostelCard extends StatelessWidget {
  final Hostel hostel;
  final VoidCallback onEdit;
  final VoidCallback onDelete;
  final bool isDeleting;
  final bool showDailyPrice;

  const _HifiHostelCard({
    required this.hostel,
    required this.onEdit,
    required this.onDelete,
    this.isDeleting = false,
    this.showDailyPrice = false,
  });

  @override
  Widget build(BuildContext context) {
    Future<void> openWhatsApp(String phoneNumber) async {
      final message = Uri.encodeComponent(
          'Hello, I am interested in your hostel.');
      final nativeUri = Uri.parse(
          'whatsapp://send?phone=$phoneNumber&text=$message');
      if (await canLaunchUrl(nativeUri)) {
        await launchUrl(nativeUri);
        return;
      }
      final webUri =
          Uri.parse('https://wa.me/$phoneNumber?text=$message');
      await launchUrl(webUri, mode: LaunchMode.externalApplication);
    }

    final isAc = _hostelIsAc(hostel);
    final sharings = hostel.sharings.isNotEmpty
        ? hostel.sharings
        : (isAc
            ? (hostel.rooms?.ac.isNotEmpty == true
                ? hostel.rooms!.ac
                : hostel.rooms?.nonAc ?? [])
            : (hostel.rooms?.nonAc.isNotEmpty == true
                ? hostel.rooms!.nonAc
                : hostel.rooms?.ac ?? []));
    final typeLabel =
        hostel.type.isNotEmpty ? hostel.type.join(' / ') : 'Hostel';

    return AnimatedOpacity(
      opacity: isDeleting ? 0.5 : 1.0,
      duration: const Duration(milliseconds: 300),
      child: Container(
        decoration: BoxDecoration(
          border: Border.all(color: Colors.grey.shade200),
          borderRadius: BorderRadius.circular(12),
          color: Colors.white,
          boxShadow: [
            BoxShadow(
              color: Colors.grey.withOpacity(0.1),
              blurRadius: 8,
              offset: const Offset(0, 2),
            ),
          ],
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                ClipRRect(
                  borderRadius: const BorderRadius.only(
                    topLeft: Radius.circular(12),
                    bottomLeft: Radius.circular(12),
                  ),
                  child: hostel.images.isNotEmpty
                      ? Image.network(
                          hostel.images.first,
                          width: 100,
                          height: 110,
                          fit: BoxFit.cover,
                          errorBuilder: (_, __, ___) => _placeholder(),
                        )
                      : _placeholder(),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: Padding(
                    padding: const EdgeInsets.symmetric(
                        vertical: 10, horizontal: 4),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Row(
                          children: [
                            Expanded(
                              child: Text(
                                hostel.name,
                                style: const TextStyle(
                                    fontWeight: FontWeight.bold,
                                    fontSize: 13),
                                maxLines: 2,
                                overflow: TextOverflow.ellipsis,
                              ),
                            ),
                            Container(
                              padding: const EdgeInsets.symmetric(
                                  horizontal: 6, vertical: 2),
                              decoration: BoxDecoration(
                                color: const Color(0xFFE53935),
                                borderRadius: BorderRadius.circular(4),
                              ),
                              child: Text(
                                typeLabel,
                                style: const TextStyle(
                                    color: Colors.white,
                                    fontSize: 9,
                                    fontWeight: FontWeight.bold),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 4),
                        Row(
                          children: [
                            const Icon(Icons.star,
                                color: Colors.amber, size: 13),
                            const SizedBox(width: 2),
                            Text('${hostel.rating}',
                                style: const TextStyle(fontSize: 11)),
                            const SizedBox(width: 6),
                            Container(
                              padding: const EdgeInsets.symmetric(
                                  horizontal: 5, vertical: 2),
                              decoration: BoxDecoration(
                                color: isAc
                                    ? Colors.blue.shade50
                                    : Colors.orange.shade50,
                                borderRadius: BorderRadius.circular(4),
                                border: Border.all(
                                  color: isAc
                                      ? Colors.blue.shade200
                                      : Colors.orange.shade200,
                                ),
                              ),
                              child: Text(
                                isAc ? 'AC' : 'Non-AC',
                                style: TextStyle(
                                  fontSize: 9,
                                  color: isAc
                                      ? Colors.blue.shade700
                                      : Colors.orange.shade700,
                                  fontWeight: FontWeight.bold,
                                ),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 4),
                        Row(
                          children: [
                            const Icon(Icons.location_on,
                                size: 11, color: Colors.grey),
                            const SizedBox(width: 2),
                            Expanded(
                              child: Text(
                                hostel.address,
                                style: const TextStyle(
                                    fontSize: 10, color: Colors.grey),
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis,
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 8),
                        Wrap(
                          spacing: 4,
                          runSpacing: 4,
                          children: sharings.take(4).map((s) {
                            final double? price = showDailyPrice
                                ? (s.dailyPrice ??
                                    s.acDailyPrice ??
                                    s.nonAcDailyPrice)
                                : (s.monthlyPrice ??
                                    s.acMonthlyPrice ??
                                    s.nonAcMonthlyPrice);
                            return Container(
                              padding: const EdgeInsets.symmetric(
                                  horizontal: 6, vertical: 3),
                              decoration: BoxDecoration(
                                color: const Color(0xFFE53935),
                                borderRadius: BorderRadius.circular(4),
                              ),
                              child: Text(
                                '${s.shareType}: ₹${price?.toStringAsFixed(0) ?? '-'}/${showDailyPrice ? 'day' : 'mo'}',
                                style: const TextStyle(
                                  color: Colors.white,
                                  fontSize: 9,
                                  fontWeight: FontWeight.bold,
                                ),
                              ),
                            );
                          }).toList(),
                        ),
                      ],
                    ),
                  ),
                ),
              ],
            ),
            Padding(
              padding: const EdgeInsets.fromLTRB(10, 6, 10, 10),
              child: Wrap(
                spacing: 6,
                runSpacing: 6,
                children: [
                  _ActionBtn(
                    icon: Icons.call,
                    label: 'Call',
                    color: const Color(0xFF4CAF50),
                    onTap: () async {
                      final uri = Uri(scheme: 'tel', path: '9961593179');
                      if (await canLaunchUrl(uri)) await launchUrl(uri);
                    },
                  ),
                  _ActionBtn(
                    icon: Icons.chat_bubble_outline,
                    label: 'Whatsapp',
                    color: const Color(0xFF25D366),
                    onTap: () => openWhatsApp('919961593179'),
                  ),
                  _ActionBtn(
                    icon: Icons.location_on,
                    label: 'Location',
                    color: const Color(0xFF2196F3),
                    onTap: () {},
                  ),
                  _ActionBtn(
                    icon: Icons.edit,
                    label: 'Edit',
                    color: const Color(0xFFE53935),
                    onTap: onEdit,
                  ),
                  _ActionBtn(
                    icon: isDeleting ? null : Icons.delete_outline,
                    label: isDeleting ? '...' : 'Delete',
                    color: const Color(0xFF757575),
                    onTap: isDeleting ? () {} : onDelete,
                    isLoading: isDeleting,
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _placeholder() => Container(
        width: 100,
        height: 110,
        decoration: BoxDecoration(
          color: Colors.grey.shade200,
          borderRadius: const BorderRadius.only(
            topLeft: Radius.circular(12),
            bottomLeft: Radius.circular(12),
          ),
        ),
        child: const Icon(Icons.apartment, size: 40, color: Colors.grey),
      );
}

