  Widget _buildField(TextEditingController c, String hint,
          {int maxLines = 1}) =>
      TextField(
        controller: c,
        maxLines: maxLines,
        keyboardType: maxLines == 1
            ? TextInputType.text
            : TextInputType.multiline,
        decoration: InputDecoration(
          hintText: hint,
          hintStyle:
              const TextStyle(color: Colors.black38, fontSize: 14),
          contentPadding: const EdgeInsets.symmetric(
              horizontal: 14, vertical: 12),
          enabledBorder: OutlineInputBorder(
            borderRadius: BorderRadius.circular(8),
            borderSide: BorderSide(color: Colors.grey.shade300),
          ),
          focusedBorder: OutlineInputBorder(
            borderRadius: BorderRadius.circular(8),
            borderSide: const BorderSide(color: Color(0xFFE53935)),
          ),
        ),
      );

  Widget _buildPriceSection(String label) => Padding(
        padding: const EdgeInsets.symmetric(horizontal: 16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            if (_isAcEnabled) ...[
              Text('$label Prices for AC',
                  style: const TextStyle(
                      fontWeight: FontWeight.bold, fontSize: 14)),
              const SizedBox(height: 8),
              _buildGrid(label == 'Monthly' ? _monthlyAc : _dailyAc,
                  Colors.blue.shade700),
              const SizedBox(height: 10),
            ] else ...[
              Text('$label Prices for Non-AC',
                  style: const TextStyle(
                      fontWeight: FontWeight.bold, fontSize: 14)),
              const SizedBox(height: 8),
              _buildGrid(
                  label == 'Monthly' ? _monthlyNonAc : _dailyNonAc,
                  const Color(0xFFE53935)),
              const SizedBox(height: 10),
            ],
          ],
        ),
      );

  Widget _buildGrid(
      Map<String, TextEditingController> prices, Color color) {
    final keys = prices.keys.toList();
    return GridView.builder(
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 3,
        mainAxisSpacing: 8,
        crossAxisSpacing: 8,
        childAspectRatio: 1.4,
      ),
      itemCount: keys.length,
      itemBuilder: (_, i) {
        final key = keys[i];
        return Container(
          decoration: BoxDecoration(
            color: color,
            borderRadius: BorderRadius.circular(8),
          ),
          padding: const EdgeInsets.all(6),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text(
                key,
                textAlign: TextAlign.center,
                style: const TextStyle(
                    color: Colors.white,
                    fontSize: 9,
                    fontWeight: FontWeight.w500),
              ),
              const SizedBox(height: 4),
              SizedBox(
                height: 22,
                child: TextField(
                  controller: prices[key],
                  textAlign: TextAlign.center,
                  style: const TextStyle(
                      color: Colors.white,
                      fontSize: 11,
                      fontWeight: FontWeight.bold),
                  decoration: const InputDecoration(
                    isDense: true,
                    contentPadding: EdgeInsets.zero,
                    border: InputBorder.none,
                  ),
                  keyboardType: TextInputType.number,
                ),
              ),
            ],
          ),
        );
      },
    );
  }
